xpath.script:
//
(function () {
    'use strict';
    if (!window.location.pathname.includes('/auction/display_auction')) return;

    /* ── Default positions per theme ──────────────────────────────────── */
    var DEFAULTS = {
        /* vanilla / strawberry: bottom-left, no footer, name not at screen bottom */
        'vanilla':      { bottom: '20px', left:  '20px', top: 'auto', right: 'auto' },
        'strawberry':   { bottom: '20px', left:  '20px', top: 'auto', right: 'auto' },
        /* butterscotch: player name overlay at bottom-LEFT of photo col (53% wide)
           -> move to bottom-RIGHT to stay clear */
        'butterscotch': { bottom: '20px', right: '60px', top: 'auto', left:  'auto' },
        /* cherry: fixed footer 52 px tall at bottom, full-width; player name is
           in the id-bar at the top -> sit just above the footer on the left */
        'cherry':       { bottom: '60px', left:  '20px', top: 'auto', right: 'auto' },
        /* pistah: fixed footer 52 px + player name block at bottom of photo panel
           (left 48%) -> above footer AND on the right side */
        'pistah':       { bottom: '60px', right: '60px', top: 'auto', left:  'auto' }
    };

    /* ── Resolve theme from #sellModal data-theme ─────────────────────── */
    function getTheme() {
        var sm = document.getElementById('sellModal');
        return (sm && sm.dataset.theme) ? sm.dataset.theme : 'vanilla';
    }

    /* ── Apply a position object to the panel ────────────────────────── */
    function applyPos(panel, pos) {
        panel.style.top    = pos.top    || 'auto';
        panel.style.bottom = pos.bottom || 'auto';
        panel.style.left   = pos.left   || 'auto';
        panel.style.right  = pos.right  || 'auto';
    }

    /* ── Drag behaviour (mouse) ───────────────────────────────────────── */
    function initDrag(panel) {
        var handle = document.getElementById('oc-bp-drag-handle');
        if (!handle) return;
        var dragging = false, ox = 0, oy = 0;

        handle.addEventListener('mousedown', function (e) {
            if (e.button !== 0) return;
            var r = panel.getBoundingClientRect();
            /* Switch to top/left so arithmetic is straightforward */
            panel.style.left   = r.left + 'px';
            panel.style.top    = r.top  + 'px';
            panel.style.right  = 'auto';
            panel.style.bottom = 'auto';
            ox = e.clientX - r.left;
            oy = e.clientY - r.top;
            dragging = true;
            handle.style.cursor = 'grabbing';
            e.preventDefault();
        });

        document.addEventListener('mousemove', function (e) {
            if (!dragging) return;
            var maxL = window.innerWidth  - panel.offsetWidth;
            var maxT = window.innerHeight - panel.offsetHeight;
            panel.style.left = Math.max(0, Math.min(e.clientX - ox, maxL)) + 'px';
            panel.style.top  = Math.max(0, Math.min(e.clientY - oy, maxT)) + 'px';
        });

        document.addEventListener('mouseup', function () {
            if (!dragging) return;
            dragging = false;
            handle.style.cursor = 'grab';
            /* Persist position */
            var key = 'oc-bid-pos-' + getTheme();
            try {
                localStorage.setItem(key, JSON.stringify({
                    top:    panel.style.top,
                    left:   panel.style.left,
                    bottom: 'auto',
                    right:  'auto'
                }));
            } catch (err) {}
        });
    }

    /* ── Initialise panel position ────────────────────────────────────── */
    function initPos(panel) {
        var theme = getTheme();
        var key   = 'oc-bid-pos-' + theme;
        var saved = null;
        try { saved = JSON.parse(localStorage.getItem(key)); } catch (err) {}
        applyPos(panel, saved || DEFAULTS[theme] || DEFAULTS['vanilla']);
    }

    /* ── Polling & UI update ─────────────────────────────────────────── */
    var _lastTeamId = null;
    var _lastBidAmt = 0;

    /* ── Edit-bid mode ────────────────────────────────────────────── */
    function enterEditMode() {
        var ptsRow = document.querySelector('.oc-bp-pts-row');
        var form   = document.getElementById('oc-bp-edit-form');
        var input  = document.getElementById('oc-bp-edit-input');
        if (!form || !input) return;
        input.value = _lastBidAmt || '';
        if (ptsRow) ptsRow.style.display = 'none';
        form.classList.add('oc-bp-edit-open');
        input.focus();
        input.select();
    }

    function exitEditMode() {
        var ptsRow = document.querySelector('.oc-bp-pts-row');
        var form   = document.getElementById('oc-bp-edit-form');
        if (ptsRow) ptsRow.style.display = '';
        if (form)  form.classList.remove('oc-bp-edit-open');
    }

    function saveCorrectBid() {
        var input   = document.getElementById('oc-bp-edit-input');
        var saveBtn = document.getElementById('oc-bp-save-btn');
        if (!input) return;
        var newVal = parseInt(input.value, 10);
        if (!newVal || newVal <= 0) {
            input.style.borderColor = '#ff4444';
            setTimeout(function () { input.style.borderColor = ''; }, 1200);
            return;
        }
        if (saveBtn) { saveBtn.disabled = true; saveBtn.innerHTML = '&#x23F3;'; }
        fetch('/auction/auctioneer/correct-bid', {
            method:  'POST',
            headers: { 'Content-Type': 'application/json' },
            body:    JSON.stringify({ jsonrpc:'2.0', method:'call', params:{ new_bid: newVal } }),
        })
        .then(function (r) { return r.json(); })
        .then(function (res) {
            var result = res.result || res;
            if (result && result.success) {
                _lastBidAmt = newVal;
                var pts = document.getElementById('oc-bp-pts');
                if (pts) pts.textContent = newVal.toLocaleString() + ' pts';
                exitEditMode();
            } else {
                alert('Could not correct bid: ' + ((result && result.error) || 'Unknown error'));
            }
        })
        .catch(function () { alert('Network error — bid not saved.'); })
        .finally(function () {
            if (saveBtn) { saveBtn.disabled = false; saveBtn.innerHTML = '&#x2714;'; }
        });
    }

    function initEditControls() {
        var editBtn   = document.getElementById('oc-bp-edit-btn');
        var saveBtn   = document.getElementById('oc-bp-save-btn');
        var cancelBtn = document.getElementById('oc-bp-cancel-btn');
        var input     = document.getElementById('oc-bp-edit-input');
        if (editBtn)   editBtn.addEventListener('click',   enterEditMode);
        if (saveBtn)   saveBtn.addEventListener('click',   saveCorrectBid);
        if (cancelBtn) cancelBtn.addEventListener('click', exitEditMode);
        if (input) {
            input.addEventListener('keydown', function (e) {
                if (e.key === 'Enter')  { e.preventDefault(); saveCorrectBid(); }
                if (e.key === 'Escape') { e.preventDefault(); exitEditMode(); }
            });
        }
    }

    function updateBidPanel(d) {
        var panel = document.getElementById('oc-bid-panel');
        var live  = document.getElementById('oc-bp-live');
        var open  = document.getElementById('oc-bp-open');
        var logo  = document.getElementById('oc-bp-logo');
        var team  = document.getElementById('oc-bp-team');
        var pts   = document.getElementById('oc-bp-pts');
        if (!panel) return;

        panel.classList.add('oc-bp-visible');

        if (d.has_bid) {
            var changed = d.current_bid !== _lastBidAmt || d.team_id !== _lastTeamId;
            if (changed) {
                _lastBidAmt = d.current_bid;
                _lastTeamId = d.team_id;
                panel.classList.remove('oc-bp-flash');
                void panel.offsetWidth;
                panel.classList.add('oc-bp-flash');
                setTimeout(function () { panel.classList.remove('oc-bp-flash'); }, 650);
            }
            if (logo) {
                logo.src           = d.team_logo_url || '';
                logo.style.display = d.team_logo_url ? 'block' : 'none';
            }
            if (team) team.textContent = d.team_name || '---';
            if (pts)  pts.textContent  = d.current_bid
                ? d.current_bid.toLocaleString() + ' pts' : '---';
            if (open) open.style.display = 'none';
            if (live) live.style.display  = 'flex';
        } else {
            _lastBidAmt = 0;
            _lastTeamId = null;
            if (live) live.style.display  = 'none';
            if (open) open.style.display  = 'block';
        }
    }

    function poll() {
        fetch('/auction/owner/live-bid', { cache: 'no-store' })
            .then(function (r) { return r.ok ? r.json() : null; })
            .then(function (d) { if (d) updateBidPanel(d); })
            .catch(function () {});
    }

    /* ── Boot ────────────────────────────────────────────────────────── */
    document.addEventListener('DOMContentLoaded', function () {
        var panel = document.getElementById('oc-bid-panel');
        if (!panel) return;
        initPos(panel);
        initDrag(panel);
        initEditControls();
    });

    poll();
    setInterval(poll, 2000);
})();
//
